from __future__ import annotations
from html import escape
from .audit import AuditResult

def render_html(result: AuditResult) -> str:
    b = result.business
    rows = []
    for f in result.findings:
        pct = int((f.score / f.max_score) * 100) if f.max_score else 0
        rows.append(f'''
        <section class="finding {escape(f.status)}">
          <div class="finding-top"><h3>{escape(f.label)}</h3><strong>{f.score}/{f.max_score}</strong></div>
          <div class="bar"><span style="width:{pct}%"></span></div>
          <p><b>Evidence:</b> {escape(f.evidence)}</p>
          <p><b>Recommendation:</b> {escape(f.recommendation)}</p>
        </section>''')
    actions = ''.join(f'<li>{escape(a)}</li>' for a in result.next_actions)
    headings = ''.join(f'<li>{escape(h)}</li>' for h in result.extracted.get('headings', [])[:12]) or '<li>No headings detected.</li>'
    schema = ', '.join(map(str, result.extracted.get('json_ld_types', []))) or 'None detected'
    return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>CiteLocal AI Audit — {escape(b.name)}</title><style>:root{{color-scheme:dark;--bg:#0b1020;--card:#121a31;--ink:#edf3ff;--muted:#9fb0d0;--accent:#70e1b5;--warn:#ffd166;--bad:#ff6b6b}}body{{margin:0;font-family:Inter,ui-sans-serif,system-ui,-apple-system,Segoe UI,sans-serif;background:radial-gradient(circle at top left,#1a2850,#0b1020 45%);color:var(--ink)}}main{{max-width:980px;margin:0 auto;padding:40px 20px 80px}}.hero,.finding,.panel{{background:rgba(18,26,49,.88);border:1px solid rgba(255,255,255,.1);border-radius:24px;padding:24px;box-shadow:0 20px 60px rgba(0,0,0,.28)}}.hero{{display:grid;grid-template-columns:1.2fr .8fr;gap:22px;align-items:center}}h1{{font-size:clamp(34px,6vw,64px);line-height:.95;margin:0 0 14px;letter-spacing:-.05em}}h2{{margin-top:38px}}.score{{font-size:72px;font-weight:900;color:var(--accent)}}.grade{{display:inline-block;background:rgba(112,225,181,.14);color:var(--accent);border:1px solid rgba(112,225,181,.45);padding:8px 12px;border-radius:999px;font-weight:800}}.muted{{color:var(--muted)}}.grid{{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:16px}}.finding{{margin:16px 0}}.finding-top{{display:flex;justify-content:space-between;gap:16px;align-items:center}}.bar{{height:10px;background:#26314f;border-radius:999px;overflow:hidden}}.bar span{{display:block;height:100%;background:linear-gradient(90deg,var(--accent),#79a7ff)}}.weak .bar span{{background:var(--bad)}}.medium .bar span{{background:var(--warn)}}li{{margin:8px 0}}code{{background:#0b1020;padding:2px 6px;border-radius:6px}}@media(max-width:720px){{.hero{{grid-template-columns:1fr}}}}</style></head><body><main><section class="hero"><div><div class="grade">AI Visibility Grade: {result.grade}</div><h1>{escape(b.name)} audit</h1><p class="muted">Category: {escape(b.category)} · Market: {escape(b.city)} · URL: <code>{escape(b.url)}</code></p><p>This report checks whether the website gives AI search and answer engines clean, quotable, locally specific evidence to recommend the business.</p></div><div class="panel"><div class="score">{result.overall_score}</div><p class="muted">out of 105 possible points</p></div></section><h2>Priority fixes</h2><section class="panel"><ol>{actions}</ol></section><h2>Detailed findings</h2>{''.join(rows)}<h2>Extracted page signals</h2><div class="grid"><section class="panel"><h3>Title</h3><p>{escape(str(result.extracted.get('title','')) or 'None')}</p></section><section class="panel"><h3>Meta description</h3><p>{escape(str(result.extracted.get('meta_description','')) or 'None')}</p></section><section class="panel"><h3>Schema types</h3><p>{escape(schema)}</p></section><section class="panel"><h3>Word count</h3><p>{escape(str(result.extracted.get('word_count','unknown')))}</p></section></div><section class="panel"><h3>Top headings</h3><ul>{headings}</ul></section><p class="muted">Generated by CiteLocal AI. This is a diagnostic tool and does not guarantee rankings, AI citations, traffic, or revenue.</p></main></body></html>'''
